sys_script_include.script:
var DM_RelatedDataMigrator = Class.create();
DM_RelatedDataMigrator.prototype = {
    initialize: function(core) {
        this.core = core || {};
        this._cacheRestQuery      = {};
        this._cacheAuditSigs      = {};
        this._cacheJournalSigs    = {};
    },
    migrateRelatedM2M: function(parentTable, sourceId, targetId) {
            var m2mList = this.core.discovery._discoverM2MTables(parentTable);
            if (m2mList.length === 0) {
                this.core.logStep("→ No M2M related lists discovered for " + parentTable);
                return;
            }
            for (var idx = 0; idx < m2mList.length; idx++) {
                var cfg = m2mList[idx];
                this.core.logStep("→ M2M " + cfg.name + " (" + cfg.table + ")");
                if (!this.core.discovery._tableExists(cfg.table)) {
                    this.core.logStep("  ⚠ Table " + cfg.table + " not found on target — skipping");
                    continue;
                }
                var grProbe = new GlideRecordSecure(cfg.table);
                if (!grProbe.isValidField(cfg.taskField)) {
                    this.core.logStep("  ⚠ Field " + cfg.taskField + " missing on " + cfg.table);
                    continue;
                }
                if (!grProbe.isValidField(cfg.refField)) {
                    this.core.logStep("  ⚠ Field " + cfg.refField + " missing on " + cfg.table);
                    continue;
                }
                var rows = this.core.discovery.fetchChildren(cfg.table, cfg.taskField, parentTable, sourceId);
                this.core.logStep("  Source rows fetched: " + rows.length);
                if (rows.length === 0 && cfg.primaryField) {
                    var record = this.core.fetchSourceRecord(parentTable, sourceId);
                    if (record) {
                        var primaryVal = this.core.discovery.normalizeRef(record[cfg.primaryField]);
                        if (primaryVal) {
                            var fakeRow = {};
                            fakeRow[cfg.refField] = primaryVal;
                            rows = [fakeRow];
                            this.core.logStep("  Fallback: using primary " + cfg.primaryField + " = " + primaryVal);
                        }
                    }
                }
                if (rows.length === 0) {
                    this.core.logStep("  No rows to migrate for " + cfg.name);
                    continue;
                }
                var migrated = 0;
                var skipped  = 0;
                var failed   = 0;
                var existingM2M = {};
                var grPre = new GlideRecordSecure(cfg.table);
                grPre.addQuery(cfg.taskField, targetId);
                grPre.setLimit(5000);
                grPre.query();
                while (grPre.next()) {
                    existingM2M[grPre.getValue(cfg.refField)] = true;
                }
                for (var i = 0; i < rows.length; i++) {
                    var row = rows[i];
                    try {
                        var srcRefVal = this.core.discovery.normalizeRef(row[cfg.refField]);
                        if (!srcRefVal) {
                            this.core.logStep("  ⚠ Row " + i + " has no " + cfg.refField);
                            skipped++;
                            continue;
						}
                        var targetRefVal = this.core.references._resolveByNameOrCreate(cfg.refTable, srcRefVal);
                        if (!targetRefVal) {
                            this.core.logStep("  ⚠ Could not resolve " + cfg.refTable + ": " + srcRefVal);
                            failed++;
                            continue;
                        }
                        if (existingM2M[targetRefVal]) {
                            if (this.core.DEBUG) this.core.logStep("    Already exists: " + cfg.table + " (" + targetId + ", " + targetRefVal + ")");
                            skipped++;
                            continue;
                        }
                        var rec = new GlideRecordSecure(cfg.table);
                        rec.initialize();
                        rec.setValue(cfg.taskField, targetId);
                        rec.setValue(cfg.refField,  targetRefVal);
                        for (var k in row) {
                            if (k === "sys_id" || k === cfg.taskField || k === cfg.refField) continue;
                            if (!rec.isValidField(k)) continue;
                            var v = row[k];
                            if (v && typeof v === "object" && v.value !== undefined) v = v.value;
                            if (v === undefined || v === null || v === "") continue;
                            try { rec.setValue(k, v); } catch (eSet) {}
                        }
                        var newRowId = rec.insert();
                        if (newRowId) {
                            existingM2M[targetRefVal] = true;  /* mark for in-batch dedup */
                            migrated++;
                            this.core.currentRecordLog.related_migrated++;
                            if (this.core.DEBUG) this.core.logStep("    ✔ Inserted " + cfg.table + ": " + targetId + " → " + targetRefVal);
                        } else {
                            this.core.logStep("  ⚠ Insert returned empty for " + cfg.table);
                            failed++;
                        }
                    } catch (e) {
                        this.core.logStep("  ⚠ Row " + i + " threw: " + e);
                        failed++;
                    }
                }
                this.core.logStep("  " + cfg.name + " summary — migrated:" + migrated +
                             " skipped:" + skipped + " failed:" + failed);
            }
        },
    migrateRelatedReferenceFields: function(parentTable, sourceId, targetId) {
            if (!this.core.RELATED_REFERENCE_FIELDS || this.core.RELATED_REFERENCE_FIELDS.length === 0)
                return;
            var srcRecord = this.core.fetchSourceRecord(parentTable, sourceId);
            for (var i = 0; i < this.core.RELATED_REFERENCE_FIELDS.length; i++) {
                var cfg = this.core.RELATED_REFERENCE_FIELDS[i];
                if (!cfg.enabled || !cfg.field) continue;
                this.core.logStep("→ Related reference field: " + cfg.name + " (" + cfg.field + ")");
                if (srcRecord && srcRecord.hasOwnProperty(cfg.field)) {
                    this.core.logStep("  [UR-DIAG] Direction A: parent has " + cfg.field +
                                  " = '" + srcLinkedId + "' (source-side)");
                    if (srcLinkedId) {
                        var refTable = cfg.refTable || "task";
                        var srcLinkedRec = this.core.fetchSourceRecord(refTable, srcLinkedId);
                        if (!srcLinkedRec) {
                            srcLinkedRec = this.core.fetchSourceRecord("universal_request", srcLinkedId);
                            if (srcLinkedRec) {
                                this.core.logStep("  [UR-DIAG] Source record only readable via universal_request table");
                                refTable = "universal_request";
                            }
                        }
                        if (!srcLinkedRec) {
                            this.core.logStep("  [UR-DIAG] ⚠ Linked record " + srcLinkedId +
                                          " NOT FOUND on source — orphan ref or REST access denied. Skipping UR.");
                            continue;
                        }
                        this.core.logStep("  [UR-DIAG] Source record fetched OK. sys_class_name = '" +
                                      this.core.discovery.normalizeRef(srcLinkedRec.sys_class_name) + "'");
                        try {
                            var newLinkedId = this.core.migrateWithDependencies(
                                refTable, srcLinkedId, 1
                            );
                            this.core.logStep("  [UR-DIAG] migrateWithDependencies returned: '" +
                                          newLinkedId + "'");
                            if (newLinkedId) {
                                var grParent = new GlideRecord(parentTable);
                                if (grParent.get(targetId) &&
                                    grParent.isValidField(cfg.field)) {
                                    var current = this.core.discovery.normalizeRef(grParent.getValue(cfg.field));
                                    this.core.logStep("  [UR-DIAG] Parent " + parentTable + "/" + targetId +
                                                  " currently has " + cfg.field + " = '" + current +
                                                  "', updating to '" + newLinkedId + "'");
                                    if (current !== newLinkedId) {
                                        grParent.setValue(cfg.field, newLinkedId);
                                        var updRes = grParent.update();
                                        this.core.logStep("  [UR-DIAG] Parent re-link update() returned: '" + updRes + "'");
                                    }
                                } else {
                                    this.core.logStep("  [UR-DIAG] ⚠ Could not get parent " + parentTable +
                                                  "/" + targetId + " OR field " + cfg.field + " not valid");
                                }
                                this.migrateActivityStreamFor(refTable, srcLinkedId, newLinkedId);
                                this.core.currentRecordLog.references_migrated++;
                                this.core.logStep("  ✔ Direction A: " + cfg.field + " = " + newLinkedId);
                                var siblingsKey = "siblings_" + refTable + "_" + srcLinkedId;
                                if (!this.core._refDeepDone[siblingsKey]) {
                                    this.core._refDeepDone[siblingsKey] = true;
                                    try {
                                        this.core.logStep("  → Pulling UR siblings (other records pointing to this UR)");
                                        this._migrateReverseRefField(cfg, srcLinkedId, newLinkedId);
                                    } catch (eSib) {
                                        this.core.logStep("  ⚠ Sibling pull threw: " + eSib);
                                    }
                                }
                            } else {
                                this.core.logStep("  ⚠ Direction A: could not migrate linked " +
                                              refTable + " " + srcLinkedId);
                            }
                        } catch (eA) {
                            this.core.logStep("  ⚠ Direction A threw: " + eA);
                        }
                    } else {
                        this.core.logStep("  [UR-DIAG] Parent's " + cfg.field + " field is empty — no UR to migrate");
                    }
                } else {
                    this.core.logStep("  [UR-DIAG] Source record does not have field " + cfg.field +
                                  " (parent table " + parentTable + " has no UR field)");
                }
                if (cfg.reverseDirection) {
                    this._migrateReverseRefField(cfg, sourceId, targetId);
                }
            }
        },
    _migrateReverseRefField: function(cfg, sourceId, targetId) {

            this.core.logStep("  Direction B: searching for incoming " + cfg.field + " refs");
            var baseUrl = this.core.SOURCE_URL.replace(/\/+$/, '');
            var api     = new sn_ws.RESTMessageV2();
            api.setEndpoint(
                baseUrl +
                "/api/now/table/sys_dictionary" +
                "?sysparm_query=" + encodeURIComponent(
                    "element=" + cfg.field + "^internal_type=reference"
                ) +
                "&sysparm_fields=name,element,reference" +
                "&sysparm_limit=10000" +
                "&sysparm_display_value=false"
            );
            api.setHttpMethod("GET");
            api.setBasicAuth(this.core.SOURCE_USER, this.core.SOURCE_PSWD);
            var resp = api.execute();
            if (resp.getStatusCode() != 200) {
                this.core.logStep("  [DIR-B] ⚠ sys_dictionary query HTTP " + resp.getStatusCode());
                return;
            }
            var rows = JSON.parse(resp.getBody()).result || [];
            this.core.logStep("  [DIR-B] dictionary query for element='" + cfg.field +
                          "' returned " + rows.length + " tables that have this field");
            var tablesFound = {};
            for (var i = 0; i < rows.length; i++) {
                if (rows[i].name) {
                    tablesFound[rows[i].name] = true;
                    if (this.core.DEBUG) {
                        var refStr = rows[i].reference;
                        if (refStr && typeof refStr === "object") refStr = refStr.value;
                        this.core.logStep("  [DIR-B]   has field: " + rows[i].name +
                                      " (references " + refStr + ")");
                    }
                }
            }
            var foundCount = 0;
            for (var fc in tablesFound) if (tablesFound.hasOwnProperty(fc)) foundCount++;
            this.core.logStep("  [DIR-B] " + foundCount + " unique tables have a '" +
                          cfg.field + "' reference field");
            var totalMigrated = 0;
            for (var tableName in tablesFound) {
                if (!tablesFound.hasOwnProperty(tableName))     continue;
                if (this.core.SKIP_TABLES[tableName])                { this.core.logStep("  [DIR-B] skip " + tableName + " (SKIP_TABLES)"); continue; }
                if (tableName === "sys_dictionary")             continue;
                if (tableName === "sys_db_object")              continue;
                if (this.core.discovery._isNoiseTable(tableName))              { this.core.logStep("  [DIR-B] skip " + tableName + " (noise table)"); continue; }
                var matchRows = this.core.discovery.fetchChildren(tableName, cfg.field, "", sourceId);
                this.core.logStep("  [DIR-B] " + tableName + " query (" + cfg.field +
                              "=" + sourceId + ") returned " + matchRows.length + " row(s)");
                if (matchRows.length === 0) continue;
                this.core.logStep("    " + tableName + ": " + matchRows.length + " incoming row(s)");
                for (var r = 0; r < matchRows.length; r++) {
                    var row    = matchRows[r];
                    var rowSid = this.core.discovery.normalizeRef(row.sys_id);
                    if (!rowSid) continue;
                    try {
                        var newRowId = this.core.migrateWithDependencies(tableName, rowSid, 1);
                        if (newRowId) {
                            this.core.references._setMigrated(tableName, rowSid, newRowId);
                            var grChild = new GlideRecord(tableName);
                            if (grChild.get(newRowId) &&
                                grChild.isValidField(cfg.field) &&
                                this.core.discovery.normalizeRef(grChild.getValue(cfg.field)) !== targetId) {
                                grChild.setValue(cfg.field, targetId);
                                grChild.update();
                                this.core.logStep("    [DIR-B] relinked " + cfg.field +
                                              " on " + tableName + "/" + newRowId +
                                              " → " + targetId);
                            }
                            this.migrateActivityStreamFor(tableName, rowSid, newRowId);
                            totalMigrated++;
                        }
                    } catch (eB) {
                        this.core.logStep("    ⚠ " + tableName + " row " + rowSid + " threw: " + eB);
                    }
                }
            }
            this.core.logStep("  Direction B summary — migrated:" + totalMigrated);
        },
    migrateDocumentIdRelations: function(parentTable, sourceId, targetId) {
            var relations = this.core.discovery._discoverDocumentIdRelations();
            if (relations.length === 0) return;
            var parentChain = this.core.discovery._getTableHierarchy(parentTable);
            var totalAttempted = 0;
            var totalMigrated  = 0;
            for (var i = 0; i < relations.length; i++) {
                var rel = relations[i];
                var query;
                if (rel.tableNameField) {
                    var clauses = [];
                    for (var c = 0; c < parentChain.length; c++) {
                        clauses.push(rel.tableNameField + "=" + parentChain[c]);
                    }
                    query = rel.refField + "=" + sourceId + "^(" + clauses.join("^OR") + ")";
                } else {
                    query = rel.refField + "=" + sourceId;
                }
                var rows = this._restQuery(rel.childTable, query);
                if (rows.length === 0) continue;
                this.core.logStep("→ Document_id relation: " + rel.childTable +
                             " (" + rel.refField +
                             (rel.tableNameField ? " + " + rel.tableNameField : "") +
                             ") — " + rows.length + " row(s)");
                for (var r = 0; r < rows.length; r++) {
                    var row = rows[r];
                    var rowSid = this.core.discovery.normalizeRef(row.sys_id);
                    if (!rowSid) continue;
                    totalAttempted++;
                    try {
                        var newRowId = this.core.migrateWithDependencies(rel.childTable, rowSid, 1);
                        if (!newRowId) {
                            this.core.logStep("  ⚠ Could not migrate " + rel.childTable + " row " + rowSid);
                            continue;
                        }
                        var fix = new GlideRecordSecure(rel.childTable);
                        if (fix.get(newRowId)) {
                            var needUpdate = false;
                            if (fix.isValidField(rel.refField) &&
                                this.core.discovery.normalizeRef(fix.getValue(rel.refField)) !== targetId) {
                                fix.setValue(rel.refField, targetId);
                                needUpdate = true;
                            }
                            if (rel.tableNameField &&
                                fix.isValidField(rel.tableNameField) &&
                                this.core.discovery.normalizeRef(fix.getValue(rel.tableNameField)) !== parentTable) {
                                fix.setValue(rel.tableNameField, parentTable);
                                needUpdate = true;
                            }
                            if (needUpdate) {
                                fix.update();
                            }
                        }
                        this.migrateActivityStreamFor(rel.childTable, rowSid, newRowId);
                        totalMigrated++;
                        this.core.currentRecordLog.related_migrated++;
                        if (this.core.DEBUG) {
                            this.core.logStep("    ✔ " + rel.childTable + " " + rowSid + " → " + newRowId);
                        }
                    } catch (e) {
                        this.core.logStep("  ⚠ " + rel.childTable + " row " + rowSid + " threw: " + e);
                    }
                }
            }
            if (totalAttempted > 0) {
                this.core.logStep("Document_id relations summary — attempted:" + totalAttempted +
                             " migrated:" + totalMigrated);
            }
        },
    _restQuery: function(table, query) {
            if (!table || !query) return [];
            if (!this._cacheRestQuery) this._cacheRestQuery = {};
            var rk = table + "::" + query;
            if (this._cacheRestQuery.hasOwnProperty(rk)) {
                return this._cacheRestQuery[rk];
            }
            var api     = new sn_ws.RESTMessageV2();
            var baseUrl = this.core.SOURCE_URL.replace(/\/+$/, '');
            api.setEndpoint(
                baseUrl +
                "/api/now/table/" + table +
                "?sysparm_query=" + encodeURIComponent(query) +
                "&sysparm_limit=10000" +
                "&sysparm_display_value=false"
            );
            api.setHttpMethod("GET");
            api.setBasicAuth(this.core.SOURCE_USER, this.core.SOURCE_PSWD);
            var response = api.execute();
            if (response.getStatusCode() != 200) {
                if (this.core.DEBUG) {
                    gs.warn("⚠ _restQuery " + table + " HTTP " +
                            response.getStatusCode() + " query=" + query);
                }
                this._cacheRestQuery[rk] = [];
                return [];
            }
            var rows = JSON.parse(response.getBody()).result || [];
            this._cacheRestQuery[rk] = rows;
            return rows;
        },
    migrateRelatedLists: function(parentTable, sourceId, targetId, depth) {
            depth = depth || 1;
            if (depth > this.core.MAX_RELATED_DEPTH) {
                if (this.core.DEBUG) this.core.logStep("  ⊘ MAX_RELATED_DEPTH (" + this.core.MAX_RELATED_DEPTH +
                                              ") reached for " + parentTable + "/" + sourceId);
                return;
            }
            if (this.core._deepStats.migrated >= this.core.MAX_DEEP_RECORDS) {
                if (!this.core._deepStats.capped) {
                    this.core.logStep("  ⊘ MAX_DEEP_RECORDS cap (" + this.core.MAX_DEEP_RECORDS +
                                 ") reached — further deep recursion suppressed");
                    this.core._deepStats.capped = true;
                }
                return;
            }
            var deepKey = "deep_" + parentTable + "_" + sourceId;
            if (depth > 1 && this.core._visited[deepKey]) {
                if (this.core.DEBUG) this.core.logStep("  ⊘ Already deep-processed " + parentTable + "/" + sourceId);
                return;
            }
            this.core._visited[deepKey] = true;
            var lists = this.core.discovery.discoverRelatedLists(parentTable);
            if (lists.length > 0 && depth === 1) this.core.logStep("Processing related lists");
            if (lists.length > 0 && depth > 1) {
                this.core.logStep("  [depth " + depth + "] Processing related lists for " +
                              parentTable + "/" + sourceId);
            }
            for (var i = 0; i < lists.length; i++) {
                var rl       = lists[i];
                var children = this.core.discovery.fetchChildren(rl.childTable, rl.refField, parentTable, sourceId);
                for (var j = 0; j < children.length; j++) {
                    var child = children[j];
                    try {
                        if (rl.childTable === "sys_journal_field"  ||
                            rl.childTable === "sys_audit"          ||
                            rl.childTable === "sys_audit_relation" ||
                            rl.childTable === "sys_history_set"    ||
                            rl.childTable === "sys_history_line"   ||
                            rl.childTable === "sys_email") continue;
                        if (this.core.SKIP_TABLES[rl.childTable]) continue;
                        if (rl.childTable === "metric_instance") {
                            var mExists = new GlideRecordSecure("metric_instance");
                            mExists.addQuery("id",         targetId);
                            mExists.addQuery("definition", child.definition);
                            mExists.addQuery("start",      child.start);
                            mExists.setLimit(1);
                            mExists.query();
                            if (mExists.next()) continue;
                            child.id    = targetId;
                            child.table = parentTable;
                            child = this.core.references._preResolveIdentityFields(child);
                            child = this.core.references._remapChildRefs(child, "metric_instance");
                            this.core.safeUpsert(child, "metric_instance", child.sys_id);
                            this.core.currentRecordLog.related_migrated++;
                            this.core._incrementProgress();
                            continue;
                        }
                        if (this.core.discovery._isTaskDerived(rl.childTable)) {
                            var fullId = this.core.migrateWithDependencies(rl.childTable, child.sys_id, 1);
                            if (fullId) {
                                this.core.references._setMigrated(rl.childTable, child.sys_id, fullId);
                                if (rl.refField) {
                                    var grLink = new GlideRecord(rl.childTable);
                                    if (grLink.get(fullId) &&
                                        this.core.discovery.normalizeRef(grLink.getValue(rl.refField)) !== targetId) {
                                        grLink.setValue(rl.refField, targetId);
                                        grLink.update();
                                    }
                                }
                                this.migrateActivityStreamFor(rl.childTable, child.sys_id, fullId);
                                this.core.currentRecordLog.related_migrated++;
                                this.core._deepStats.migrated++;
                                this.core._incrementProgress();
                                if (this.core.DEEP_RECURSION_ENABLED &&
                                    this.core.DEEP_RECURSE_TABLES[rl.childTable] &&
                                    depth < this.core.MAX_RELATED_DEPTH) {
                                    this._deepRecurseRelated(rl.childTable, child.sys_id, fullId, depth + 1);
                                }
                            }
                            continue;
                        }
                        if (rl.refField) child[rl.refField] = targetId;
                        child = this.core.references._preResolveIdentityFields(child);
                        var skip = {};
                        if (rl.refField) skip[rl.refField] = true;
                        child = this.core.references._remapChildRefs(child, rl.childTable, 1, skip);
                        if (rl.refField) child[rl.refField] = targetId;
                        var _alreadyKey = rl.childTable + "_" + child.sys_id;
                        if (this.core._migratedRecords[_alreadyKey]) {
                            if (rl.refField) {
                                var grRe = new GlideRecord(rl.childTable);
                                if (grRe.get(this.core._migratedRecords[_alreadyKey]) &&
                                    grRe.isValidField(rl.refField) &&
                                    this.core.discovery.normalizeRef(grRe.getValue(rl.refField)) !== targetId) {
                                    grRe.setValue(rl.refField, targetId);
                                    grRe.update();
                                }
                            }
                            continue;
                        }
                        var childTargetId = this.core.safeUpsert(child, rl.childTable, child.sys_id);
                        if (childTargetId) this.core.references._setMigrated(rl.childTable, child.sys_id, childTargetId);
                        this.core.currentRecordLog.related_migrated++;
                        this.core._incrementProgress();
                    } catch (e) {
                        this.core.currentRecordLog.related_failed++;
                        this.core.currentRecordLog.errors.push("Related failed: " + rl.childTable);
                        gs.warn("Related record failed: " + rl.childTable + " — " + e);
                    }
                }
            }
            if (depth === 1) {
                this._migrateApprovalsRecursive(parentTable, sourceId, targetId);
            }
        },
    _deepRecurseRelated: function(childTable, srcSysId, targetSysId, depth) {
            if (!this.core.DEEP_RECURSION_ENABLED) return;
            if (depth > this.core.MAX_RELATED_DEPTH) return;
            if (this.core._deepStats.migrated >= this.core.MAX_DEEP_RECORDS) return;
            if (this.core.DEBUG) {
                this.core.logStep("  ↳ [depth " + depth + "] deep-recursing " + childTable + "/" + srcSysId);
            }
            try {
                this.migrateTaskRelationships(childTable, srcSysId, targetSysId);
                this.migrateRelatedM2M(childTable, srcSysId, targetSysId);
                this.migrateRelatedLists(childTable, srcSysId, targetSysId, depth);
                this.copyAttachments(childTable, srcSysId, targetSysId);
                this.insertSLAs(srcSysId, targetSysId);
                this.migrateActivityStreamFor(childTable, srcSysId, targetSysId);
            } catch (e) {
                gs.warn("Deep recurse failed: " + childTable + "/" + srcSysId + " — " + e);
            }
        },
    _migrateApprovalsRecursive: function(parentTable, sourceId, targetId) {
            try {
                var approvalTargets = [{ source: sourceId, target: targetId, table: parentTable }];
                if (parentTable === "sc_request") {
                    var ritms = this.core.discovery.fetchChildren("sc_req_item", "request", parentTable, sourceId);
                    for (var r = 0; r < ritms.length; r++) {
                        var ritm         = ritms[r];
                        var targetRitmId = this.core.migrateWithDependencies("sc_req_item", ritm.sys_id, 1);
                        if (targetRitmId) this.core.references._setMigrated("sc_req_item", ritm.sys_id, targetRitmId);
                        approvalTargets.push({ source: ritm.sys_id, target: targetRitmId, table: "sc_req_item" });
                        if (targetRitmId)
                            this.migrateActivityStreamFor("sc_req_item", ritm.sys_id, targetRitmId);
                        var tasks = this.core.discovery.fetchChildren("sc_task", "request_item", "sc_req_item", ritm.sys_id);
                        for (var tk = 0; tk < tasks.length; tk++) {
                            var task         = tasks[tk];
                            var targetTaskId = this.core.migrateWithDependencies("sc_task", task.sys_id, 1);
                            if (targetTaskId) this.core.references._setMigrated("sc_task", task.sys_id, targetTaskId);
                            approvalTargets.push({ source: task.sys_id, target: targetTaskId, table: "sc_task" });
                            if (targetTaskId)
                                this.migrateActivityStreamFor("sc_task", task.sys_id, targetTaskId);
                        }
                    }
                }
                for (var a = 0; a < approvalTargets.length; a++) {
                    var pair      = approvalTargets[a];
                    var approvals = this.core.discovery.fetchChildren("sysapproval_approver", "sysapproval", "", pair.source);
                    for (var x = 0; x < approvals.length; x++) {
                        var appr = approvals[x];
                        try {
                            appr.sysapproval = pair.target;
                            appr = this.core.references._preResolveIdentityFields(appr);
                            var skipAppr = { sysapproval: true };
                            appr = this.core.references._remapChildRefs(appr, "sysapproval_approver", 1, skipAppr);
                            appr.sysapproval = pair.target;
                            this.core.safeUpsert(appr, "sysapproval_approver", appr.sys_id);
                        } catch (eAppr) { gs.warn("Approval migration failed"); }
                    }
                }
            } catch (e) {
                gs.error("Approval recursion failed: " + e);
            }
        },
    migrateActivityStreamFor: function(table, sourceId, targetId) {
            if (!sourceId || !targetId) return;
            if (this.core.FAST_MODE) {
                if (this.core.DEBUG) this.core.logStep("  ⏩ FAST_MODE: skipping activity stream for " + table + "/" + sourceId);
                return;
            }
            if (!this.core._activityStreamDone) this.core._activityStreamDone = {};
            var guardKey = table + "_" + sourceId;
            if (this.core._activityStreamDone[guardKey]) return;
            this.core._activityStreamDone[guardKey] = true;
            try {
                this.migrateAuditFor(table, sourceId, targetId);
                this.migrateJournalFor(table, sourceId, targetId);
                this.migrateHistorySetsFor(table, sourceId, targetId);
                this.migrateEmailFor(table, sourceId, targetId);
            } catch (e) {
                gs.warn("⚠ migrateActivityStreamFor failed: " + table + "/" + sourceId + " — " + e);
            }
        },
    _fetchAuditRows: function(auditTable, parentTable, sourceId) {
            var api     = new sn_ws.RESTMessageV2();
            var baseUrl = this.core.SOURCE_URL.replace(/\/+$/, '');
            var query = (auditTable === "sys_audit_relation")
                ? "documentkey=" + sourceId
                : "documentkey=" + sourceId + "^tablename=" + parentTable;
            api.setEndpoint(
                baseUrl +
                "/api/now/table/" + auditTable +
                "?sysparm_query=" + encodeURIComponent(query) +
                "&sysparm_limit=5000" +
                "&sysparm_display_value=false"
            );
            api.setHttpMethod("GET");
            api.setBasicAuth(this.core.SOURCE_USER, this.core.SOURCE_PSWD);
            var response = api.execute();
            if (response.getStatusCode() != 200) return [];
            return JSON.parse(response.getBody()).result || [];
        },
    migrateAuditFor: function(table, sourceId, targetId) {
            var auditTables   = ["sys_audit", "sys_audit_relation"];
            var totalMigrated = 0;
            var totalSkipped  = 0;
            for (var t = 0; t < auditTables.length; t++) {
                var auditTable = auditTables[t];
                var audits     = this._fetchAuditRows(auditTable, table, sourceId);
                if (audits.length === 0) continue;
                this.core.references._batchPrefetchUsers(audits);
                var existingSignatures = this._loadExistingAuditSignatures(auditTable, targetId, table);
                for (var i = 0; i < audits.length; i++) {
                    var aud = audits[i];
                    try {
                        var auditCopy = {};
                        for (var k in aud) auditCopy[k] = aud[k];
                        auditCopy.documentkey = targetId;
                        if (auditTable === "sys_audit") {
                            auditCopy.tablename      = table;
                            auditCopy.sys_class_name = table;
                        }
                        if (auditCopy.user) {
                            var srcUser = this.core.discovery.normalizeRef(auditCopy.user);
                            if (srcUser) {
                                auditCopy.user = this.core._sysIdLookup[srcUser] ||
                                                  this.core.references._resolveByNaturalKey("sys_user", srcUser) || "";
                            }
                        }
                        var createdBy = this.core.discovery.normalizeRef(auditCopy.sys_created_by);
                        if (createdBy) this.core.references._ensureUserExists(createdBy);
                        if (this.core._sysIdLookup && Object.keys(this.core._sysIdLookup).length > 0) {
                            this.core.references._remapAllSysIdFieldsInRow(auditCopy, { documentkey: true });
                        }
                        var sig = (aud.fieldname || "") + "::" + (aud.sys_created_on || "");
                        if (existingSignatures[sig]) {
                            totalSkipped++;
                            continue;
                        }
                        var result = this.core.safeUpsert(auditCopy, auditTable, "");
                        if (result) {
                            totalMigrated++;
                            this.core.currentRecordLog.audit_migrated++;
                            existingSignatures[sig] = true;  // mark migrated to dedup within batch
                            this.core._auditRowsToFix.push({
                                table:        auditTable,
                                targetId:     result,
                                sysCreatedBy: createdBy
                            });
                        }
                    } catch (e) {
                        this.core.currentRecordLog.audit_failed++;
                    }
                }
            }
            this.core.logStep("Audit migrated: " + totalMigrated + ", skipped: " + totalSkipped);
        },
    _loadExistingAuditSignatures: function(auditTable, targetId, table) {
            var sigs = {};
            var gr = new GlideRecordSecure(auditTable);
            gr.addQuery("documentkey", targetId);
            if (auditTable === "sys_audit") gr.addQuery("tablename", table);
            gr.setLimit(50000);
            gr.query();
            while (gr.next()) {
                var fn = gr.getValue("fieldname") || "";
                var co = gr.getValue("sys_created_on") || "";
                sigs[fn + "::" + co] = true;
            }
            return sigs;
        },
    _auditExists: function(auditTable, targetId, table, aud) {
            var gr = new GlideRecordSecure(auditTable);
            gr.addQuery("documentkey", targetId);
            gr.addQuery("tablename",   table);
            var fieldname = String(aud.fieldname || "").trim();
            if (fieldname) gr.addQuery("fieldname", fieldname);
            gr.setLimit(1);
            gr.query();
            return gr.next();
        },
    migrateJournalFor: function(table, sourceId, targetId) {
            var journals = this.core.discovery.fetchChildren("sys_journal_field", "element_id", table, sourceId);
            var migrated = 0;
            if (journals.length === 0) return;
            var existingSigs = {};
            var grEx = new GlideRecordSecure("sys_journal_field");
            grEx.addQuery("element_id", targetId);
            grEx.addQuery("name",       table);
            grEx.setLimit(50000);
            grEx.query();
            while (grEx.next()) {
                var v = grEx.getValue("value") || "";
                var c = grEx.getValue("sys_created_on") || "";
                existingSigs[v.substring(0, 200) + "::" + c] = true;
            }
            var unameSet = {};
            for (var j2 = 0; j2 < journals.length; j2++) {
                var cb = journals[j2] && journals[j2].sys_created_by;
                if (cb && typeof cb === "object" && cb.value !== undefined) cb = cb.value;
                if (cb) unameSet[String(cb).trim()] = true;
            }
            this.core.references._ensureUserExistsBatch(unameSet);
            for (var i = 0; i < journals.length; i++) {
                var jrn = journals[i];
                try {
                    var jrnCopy = {};
                    for (var k in jrn) jrnCopy[k] = jrn[k];
                    jrnCopy.element_id = targetId;
                    var createdBy = this.core.discovery.normalizeRef(jrnCopy.sys_created_by);
                    if (createdBy && !this._cacheUserNameExists[createdBy]) {
                        this.core.references._ensureUserExists(createdBy);
                    }
                    var v2  = String(jrn.value || "");
                    var c2  = String(jrn.sys_created_on || "");
                    var sig = v2.substring(0, 200) + "::" + c2;
                    if (existingSigs[sig]) continue;
                    var result = this.core.safeUpsert(jrnCopy, "sys_journal_field", "");
                    if (result) {
                        migrated++;
                        this.core.currentRecordLog.journal_migrated++;
                        existingSigs[sig] = true;
                    }
                } catch (e) {
                    this.core.currentRecordLog.journal_failed++;
                }
            }
            this.core.logStep("Journal migrated: " + migrated);
        },
    _journalExists: function(targetId, table, jrn) {
            var gr = new GlideRecordSecure("sys_journal_field");
            gr.addQuery("element_id", targetId);
            gr.addQuery("name",       table);
            var value = String(jrn.value || "");
            if (value) gr.addQuery("value", value);
            gr.setLimit(1);
            gr.query();
            return gr.next();
        },
    migrateEmailFor: function(table, sourceId, targetId) {
            var baseUrl = this.core.SOURCE_URL.replace(/\/+$/, '');
            var api     = new sn_ws.RESTMessageV2();
            api.setEndpoint(
                baseUrl +
                "/api/now/table/sys_email" +
                "?sysparm_query=" + encodeURIComponent(
                    "instance=" + sourceId +
                    "^ORtarget=" + sourceId +
                    "^ORtarget_sys_id=" + sourceId
                ) +
                "&sysparm_limit=10000" +
                "&sysparm_display_value=false"
            );
            api.setHttpMethod("GET");
            api.setBasicAuth(this.core.SOURCE_USER, this.core.SOURCE_PSWD);
            var resp = api.execute();
            if (resp.getStatusCode() != 200) return;
            var emails = JSON.parse(resp.getBody()).result || [];
            if (emails.length === 0) return;
            var unameSet = {};
            for (var u = 0; u < emails.length; u++) {
                var cb = emails[u] && emails[u].sys_created_by;
                if (cb && typeof cb === "object" && cb.value !== undefined) cb = cb.value;
                if (cb) unameSet[String(cb).trim()] = true;
            }
            this.core.references._ensureUserExistsBatch(unameSet);
            for (var i = 0; i < emails.length; i++) {
                var email = emails[i];
                try {
                    var copy = {};
                    for (var k in email) copy[k] = email[k];
                    copy.instance      = targetId;
                    copy.target        = targetId;
                    copy.target_sys_id = targetId;
                    var createdBy = this.core.discovery.normalizeRef(copy.sys_created_by);
                    if (createdBy && !this._cacheUserNameExists[createdBy]) {
                        this.core.references._ensureUserExists(createdBy);
                    }
                    this.core.safeUpsert(copy, "sys_email", "");
                    this.core.currentRecordLog.email_migrated++;
                } catch (e) {
                    this.core.currentRecordLog.email_failed++;
                }
            }
        },
    copyAttachments: function(table, sourceId, targetId) {
            var attachments = this.core.discovery.fetchChildren("sys_attachment", "table_sys_id", table, sourceId);
            for (var i = 0; i < attachments.length; i++) {
                var att = attachments[i];
                try {
                    var copy = {};
                    for (var k in att) copy[k] = att[k];
                    copy.table_sys_id = targetId;
                    copy.table_name   = table;
                    this.core.safeUpsert(copy, "sys_attachment", att.sys_id);
                    this.core.currentRecordLog.attachments_copied++;
                } catch (e) {
                    gs.warn("Attachment copy failed: " + att.sys_id);
                }
            }
        },
    insertSLAs: function(sourceId, targetId) {
            var slas = this.core.discovery.fetchChildren("task_sla", "task", "", sourceId);
            for (var i = 0; i < slas.length; i++) {
                var sla = slas[i];
                try {
                    var copy = {};
                    for (var k in sla) copy[k] = sla[k];
                    var slaDefSrc      = this.core.discovery.normalizeRef(copy.sla);
                    var resolvedSlaDef = '';
                    if (slaDefSrc) {
                        resolvedSlaDef = this.core.references._resolveByNaturalKey("contract_sla", slaDefSrc);
                        if (!resolvedSlaDef) {
                            var grSlaCheck = new GlideRecordSecure("contract_sla");
                            if (grSlaCheck.get(slaDefSrc)) resolvedSlaDef = slaDefSrc;
                        }
                        if (resolvedSlaDef) {
                            copy.sla = resolvedSlaDef;
                            this.core.references._setMigrated("contract_sla", slaDefSrc, resolvedSlaDef);
                        } else {
                            gs.warn("⚠ SLA definition not found on target: " + slaDefSrc);
                        }
                    }
                    copy.task = targetId;
                    copy = this.core.references._preResolveIdentityFields(copy);
                    copy = this.core.references._remapChildRefs(copy, "task_sla", 1, { sla: true, task: true });
                    copy.task = targetId;
                    if (resolvedSlaDef) copy.sla = resolvedSlaDef;
                    var dupCheck = new GlideRecordSecure("task_sla");
                    dupCheck.addQuery("task", targetId);
                    if (copy.sla) dupCheck.addQuery("sla", copy.sla);
                    dupCheck.setLimit(1);
                    dupCheck.query();
                    if (dupCheck.next()) {
                        this.core.safeUpsert(copy, "task_sla", dupCheck.getUniqueValue());
                    } else {
                        this.core.safeUpsert(copy, "task_sla", sla.sys_id);
                    }
                } catch (e) {
                    gs.warn("SLA migration failed: " + sla.sys_id + " — " + e);
                }
            }
        },
    migrateChildTasks: function(parentTable, sourceId, targetId) {
            var children = this.core.discovery.fetchChildren("task", "parent", parentTable, sourceId);
            for (var i = 0; i < children.length; i++) {
                var child = children[i];
                try {
                    var newId = this.core.migrateWithDependencies("task", child.sys_id, 1);
                    if (newId) {
                        this.core.references._setMigrated("task", child.sys_id, newId);
                        var grLink = new GlideRecordSecure("task");
                        if (grLink.get(newId) &&
                            this.core.discovery.normalizeRef(grLink.getValue("parent")) !== targetId) {
                            grLink.setValue("parent", targetId);
                            grLink.update();
                        }
                        this.migrateActivityStreamFor("task", child.sys_id, newId);
                    }
                } catch (e) {
                    gs.warn("Child task migration failed: " + e);
                }
            }
        },
    migrateChildIncidents: function(sourceId, targetId) {
            var children = this.core.discovery.fetchChildren("incident", "parent_incident", "", sourceId);
            for (var i = 0; i < children.length; i++) {
                var child = children[i];
                try {
                    var migratedChildId = this.core.migrateWithDependencies("incident", child.sys_id, 1);
                    if (migratedChildId) {
                        this.core.references._setMigrated("incident", child.sys_id, migratedChildId);
                        var grLink = new GlideRecordSecure("incident");
                        if (grLink.get(migratedChildId) &&
                            this.core.discovery.normalizeRef(grLink.getValue("parent_incident")) !== targetId) {
                            grLink.setValue("parent_incident", targetId);
                            grLink.update();
                        }
                        this.migrateActivityStreamFor("incident", child.sys_id, migratedChildId);
                    }
                } catch (e) {
                    gs.warn("Child incident migration failed: " + e);
                }
            }
        },
    migrateTaskRelationships: function(table, sourceId, targetId) {
            try {
                var record = this.core.fetchSourceRecord(table, sourceId);
                if (!record) return;
                var taskRels = this.core.discovery._discoverTaskRelationships(table);
                if (this.core.DEBUG) {
                    this.core.logStep("Task relationships discovered for " + table + ": " + taskRels.length);
                }
                for (var i = 0; i < taskRels.length; i++) {
                    var rel    = taskRels[i];
                    var srcRef = this.core.discovery.normalizeRef(record[rel.field]);
                    if (!srcRef) continue;
                    var targetRef = this.core.migrateWithDependencies(rel.table, srcRef, 1);
                    if (targetRef) {
                        var gr = new GlideRecordSecure(table);
                        if (gr.get(targetId) && gr.isValidField(rel.field)) {
                            var current = this.core.discovery.normalizeRef(gr.getValue(rel.field));
                            if (current !== targetRef) {
                                gr.setValue(rel.field, targetRef);
                                gr.update();
                            }
                        }
                        this.core.logStep("✔ Lateral " + rel.table + " resolved via " + rel.field);
                    }
                }
            } catch (e) {
                gs.warn("Task relationship migration failed: " + e);
            }
        },
    migrateM2MRelations: function(table, sourceId, targetId) {
            for (var m = 0; m < this.core.M2M_DEFINITIONS.length; m++) {
                var def     = this.core.M2M_DEFINITIONS[m];
                var allRels = [];
                var seen    = {};
                for (var fi = 0; fi < def.fields.length; fi++) {
                    var fieldDef = def.fields[fi];
                    var rels     = this.core.discovery.fetchChildren(def.table, fieldDef.field, table, sourceId);
                    for (var ri = 0; ri < rels.length; ri++) {
                        var r    = rels[ri];
                        var rsid = this.core.discovery.normalizeRef(r.sys_id);
                        if (rsid && !seen[rsid]) {
                            seen[rsid] = true;
                            allRels.push(r);
                        }
                    }
                }
                for (var idx = 0; idx < allRels.length; idx++) {
                    var rel = allRels[idx];
                    try {
                        for (var fi2 = 0; fi2 < def.fields.length; fi2++) {
                            var fd = def.fields[fi2];
                            var src = this.core.discovery.normalizeRef(rel[fd.field]);
                            if (!src) continue;
                            if (src === sourceId) {
                                rel[fd.field] = targetId;
                            } else {
                                var resolved = this.core.references._resolveRefForRelated(fd.refTable, src, 1);
                                if (resolved) rel[fd.field] = resolved;
                            }
                        }
                        var dup = new GlideRecordSecure(def.table);
                        for (var fi3 = 0; fi3 < def.fields.length; fi3++) {
                            var fd2 = def.fields[fi3];
                            if (rel[fd2.field]) dup.addQuery(fd2.field, rel[fd2.field]);
                        }
                        dup.setLimit(1);
                        dup.query();
                        if (dup.next()) continue;
                        this.core.safeUpsert(rel, def.table, rel.sys_id);
                        this.core.currentRecordLog.related_migrated++;
                    } catch (e) {
                        gs.warn("M2M migration failed: " + def.table + " — " + e);
                    }
                }
            }
        },
    migrateHistorySetsFor: function(table, sourceId, targetId) {
        },
    _migrateHistoryLinesForSet: function(sourceSetId, targetSetId) {
            var lines = this.core.discovery.fetchChildren("sys_history_line", "set", "", sourceSetId);
            for (var i = 0; i < lines.length; i++) {
                var line = lines[i];
                try {
                    var copy = {};
                    for (var k in line) copy[k] = line[k];
                    copy.set = targetSetId;
                    this.core.safeUpsert(copy, "sys_history_line", line.sys_id);
                } catch (e) {
                    gs.warn("History line migration failed");
                }
            }
        },
    verifyRelatedM2M: function(parentTable, targetTaskId) {
            var report  = [];
            var m2mList = this.core.discovery._discoverM2MTables(parentTable);
            for (var i = 0; i < m2mList.length; i++) {
                var cfg = m2mList[i];
                if (!this.core.discovery._tableExists(cfg.table)) {
                    report.push(cfg.name + " — table " + cfg.table + " not present");
                    continue;
                }
                var gr = new GlideRecordSecure(cfg.table);
                gr.addQuery(cfg.taskField, targetTaskId);
                gr.query();
                var count = 0;
                var rows  = [];
                while (gr.next()) {
                    count++;
                    rows.push(gr.getValue(cfg.refField));
                }
                report.push(
                    cfg.name + " (" + cfg.table + "): " + count + " row(s) — " +
                    (rows.length ? rows.join(", ") : "(none)")
                );
            }
            gs.info("=== Related M2M verification for " + targetTaskId + " ===\n" + report.join("\n"));
            return report;
        },
    type: 'DM_RelatedDataMigrator'
};
